head.script:
scwin.odrNo = "";
scwin.mobileLoadChk = "";
scwin.dayGijun = "";
scwin.exArvDt = "";
scwin.exDptDt = "";
scwin.dayChk = "";
scwin.clntNo = "";

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function () {    
    let params = $c.data.getParameter();

    if (!$c.util.isEmpty(params["CAR_NO"])) {
        scwin.carNo = params["CAR_NO"].replaceAll("'", "");
    }

    if (!$c.util.isEmpty(params["ODR_NO"])) {
        scwin.odrNo = params["ODR_NO"];
    }

    if (!$c.util.isEmpty(params["MOBILE_LOAD_CHK"])) {
        scwin.mobileLoadChk = params["MOBILE_LOAD_CHK"];
    }

    if (!$c.util.isEmpty(params["DAY_GIJUN"])) {
        scwin.dayGijun = params["DAY_GIJUN"];
    }

    if (!$c.util.isEmpty(params["EX_ARV_DT"])) {
        scwin.exArvDt = params["EX_ARV_DT"];
    }

    if (!$c.util.isEmpty(params["EX_DPT_DT"])) {
        scwin.exDptDt = params["EX_DPT_DT"];
    }

    if (!$c.util.isEmpty(params["DAY_CHK"])) {
        scwin.dayChk = params["DAY_CHK"];
    }

    if (!$c.util.isEmpty(params["SCH_CLNT_NO"])) {
        scwin.clntNo = params["SCH_CLNT_NO"];
    }

    //테스트 데이터
    // scwin.carNo = "경기81바5899";
    // scwin.odrNo = "18726409";
    // scwin.mobileLoadChk = "Y";
    // scwin.dayGijun = "";
    // scwin.exArvDt = "";
    // scwin.exDptDt = "";
    // scwin.dayChk = "";
    // scwin.clntNo = "000001";

    // 차량정보 조회
    scwin.f_RetrieveVehicle();
};

//-------------------------------------------------------------------------
// 차량정보 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveVehicle = function () {
    dma_Contr.set("CAR_NO", scwin.carNo);
    dma_Contr.set("ODR_NO", scwin.odrNo);
    dma_Contr.set("CLNT_NO", scwin.clntNo);

    $c.sbm.execute(sbm_RetrieveContr);
};

//-------------------------------------------------------------------------
// 지도 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveTrace = function () {
    dma_Contr2.set("qryCar", "lfz2");
    dma_Contr2.set("qryCntn", ds_Contr.getCellData(0, 'vehclNo'));
    dma_Contr2.set("pdaNo", ds_Contr.getCellData(0, 'pdaNo'));
    dma_Contr2.set("dtgNo", ds_Contr.getCellData(0, 'dtgNo'));
    dma_Contr2.set("qryEdate", ds_Contr.getCellData(0, 'dptDt'));
    dma_Contr2.set("qrySdate", ds_Contr.getCellData(0, 'maxRptDt'));
    dma_Contr2.set("Gubun", "chase");
    dma_Contr2.set("stDt", ds_Contr.getCellData(0, 'dptDt'));   
    dma_Contr2.set("endDt", ds_Contr.getCellData(0, 'arvDt'));
    dma_Contr2.set("dayGijun", scwin.dayGijun);
    dma_Contr2.set("exArvDt", scwin.exArvDt);
    dma_Contr2.set("exDptDt", scwin.exDptDt);
    dma_Contr2.set("dayChk", scwin.dayChk);

    $c.sbm.execute(sbm_Retrieve);
};

//-------------------------------------------------------------------------
// 차량리스트 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveTrace2 = function () {
    dma_Contr2.set("qryCar", "lfz2");
    dma_Contr2.set("qryCntn", ds_Contr.getCellData(0, 'vehclNo'));
    dma_Contr2.set("pdaNo", ds_Contr.getCellData(0, 'pdaNo'));
    dma_Contr2.set("dtgNo", ds_Contr.getCellData(0, 'dtgNo'));
    dma_Contr2.set("qryEdate", ds_Contr.getCellData(0, 'dptDt'));
    dma_Contr2.set("Gubun", "list");
    dma_Contr2.set("stDt", ds_Contr.getCellData(0, 'dptDt'));
    dma_Contr2.set("endDt", ds_Contr.getCellData(0, 'arvDt'));
    dma_Contr2.set("dayGijun", scwin.dayGijun);
    dma_Contr2.set("exArvDt", scwin.exArvDt);
    dma_Contr2.set("exDptDt", scwin.exDptDt);
    dma_Contr2.set("dayChk", scwin.dayChk);

    $c.sbm.execute(sbm_Retrieve2);
};

//-------------------------------------------------------------------------
// 차량정보 조회 submitdone
//-------------------------------------------------------------------------
scwin.sbm_RetrieveContr_submitdone = function (e) {
    tbx_vehclNo.setValue(ds_Contr.getCellData(0, "vehclNo"));
    tbx_picNm.setValue(ds_Contr.getCellData(0, "picNm"));
    tbx_handphoneNo.setValue(ds_Contr.getCellData(0, "handphoneNo"));

    if (ds_Contr.getCellData(0, 'pdaNo') == "" && ds_Contr.getCellData(0, 'dtgNo') == "") {
        grp_message.show("");
        tbx_message.setValue("관제장비 미장착 차량입니다.");
    } else {
        grp_message.hide();
        tbx_message.setValue("");
        scwin.f_RetrieveTrace();
        scwin.f_RetrieveTrace2();
    }
};

//-------------------------------------------------------------------------
// 조회 submitdone
//-------------------------------------------------------------------------
scwin.sbm_Retrieve_submitdone = function (e) {
    // 카카오맵
    if (ds_Trace.getRowCount() == 0) {  
        var position = new kakao.maps.LatLng("37.477785", "127.043958");
        var mapContainer = grp_map.render; // 그룹 객체아이디(grp_map) 의 div 영역지정
        var mapOption = {
            center: position
            , level: 3 // 지도의 확대 레벨
        };

        var map = new kakao.maps.Map(mapContainer, mapOption); // 지도를 생성합니다

        // 마커 이미지의 이미지 주소입니다
        var imageSrc = "http://t1.daumcdn.net/localimg/localimages/07/mapapidoc/markerStar.png";

        // 마커 이미지의 이미지 크기 입니다
        var imageSize = new kakao.maps.Size(24, 35);

        // 마커 이미지를 생성합니다    
        var markerImage = new kakao.maps.MarkerImage(imageSrc, imageSize);

        // 마커를 생성합니다
        var marker = new kakao.maps.Marker({
            map: map, // 마커를 표시할 지도
            position: position, // 마커를 표시할 위치
            title: "동원산업", // 마커의 타이틀, 마커에 마우스를 올리면 타이틀이 표시됩니다
            image: markerImage // 마커 이미지 
        });

        if (scwin.mobileLoadChk == "N") {
            $c.win.alert("모바일 출발 보고 내역이 없습니다.");
        }

        $c.win.alert("관제내역이 1건도 존재하지 않습니다.");

    } else {
        var lat = "";
        var lon = "";
        var lat1 = ds_Trace.getCellData(0, "lat");
        var lon1 = ds_Trace.getCellData(0, "lon");

        var position = new kakao.maps.LatLng(lat1, lon1);

        var mapContainer = grp_map.render; // 그룹 객체아이디(grp_map) 의 div 영역지정
        var mapOption = {
            center: position
            , level: 7 // 지도의 확대 레벨
        };

        var map = new kakao.maps.Map(mapContainer, mapOption); // 지도를 생성합니다
        var startSrc = 'http://t1.daumcdn.net/localimg/localimages/07/mapapidoc/red_b.png', // 출발 마커이미지의 주소입니다  
            startSize = new kakao.maps.Size(50, 45), // 출발 마커이미지의 크기입니다 
            startOption = {
                offset: new kakao.maps.Point(15, 43) // 출발 마커이미지에서 마커의 좌표에 일치시킬 좌표를 설정합니다 (기본값은 이미지의 가운데 아래입니다)
            };

        // 출발 마커 이미지를 생성합니다
        var startImage = new kakao.maps.MarkerImage(startSrc, startSize, startOption);

        // 출발 마커가 표시될 위치입니다 
        var startPosition = new kakao.maps.LatLng(lat1, lon1);

        // 출발 마커를 생성합니다
        var startMarker = new kakao.maps.Marker({
            map: map, // 출발 마커가 지도 위에 표시되도록 설정합니다
            position: startPosition,
            draggable: false, // 출발 마커가 드래그 가능하도록 설정합니다
            image: startImage // 출발 마커이미지를 설정합니다
        });

        // 마커 이미지의 이미지 주소입니다
        var imageSrc = "http://t1.daumcdn.net/localimg/localimages/07/mapapidoc/markerStar.png";

        for (var i = 1; i < ds_Trace.getRowCount(); i++) {
            lat = ds_Trace.getCellData(i, "lat");
            lon = ds_Trace.getCellData(i, "lon");
            addr = ds_Trace.getCellData(i, "addr") + " " + ds_Trace.getCellData(i, "rcvDt");

            var positions = new Array();

            var title = addr;
            var latlng = new kakao.maps.LatLng(lat, lon);

            positions[0] = title;
            positions[1] = latlng;

            // 마커 이미지의 이미지 크기 입니다
            var imageSize = new kakao.maps.Size(24, 35);

            // 마커 이미지를 생성합니다    
            var markerImage = new kakao.maps.MarkerImage(imageSrc, imageSize);

            // 마커를 생성합니다
            var marker = new kakao.maps.Marker({
                map: map, // 마커를 표시할 지도
                position: positions[1], // 마커를 표시할 위치
                title: positions[0], // 마커의 타이틀, 마커에 마우스를 올리면 타이틀이 표시됩니다
                image: markerImage // 마커 이미지 
            });

        }

        if (scwin.mobileLoadChk == "N") {
            $c.win.alert("모바일 출발 보고 내역이 없습니다.");
        }
    }
};

//-------------------------------------------------------------------------
// 위치추적 조회 submitdone
//-------------------------------------------------------------------------
scwin.sbm_Retrieve2_submitdone = function (e) {
    tbx_totalRows.setValue(ds_Trace2.getRowCount());
};
